/* === double =========================================================== */

static __inline__ int
json_scan_double(double *data, const char **json)
{
  int s = 0;
  double v;

  if (!strncmp(*json, "null", 4)) {
    (*json) += 4;
    *data = (double)nan("");
  } else {
    char *d;
    v = strtod(*json, &d);
    if (d == *json) return EINVAL;
    *json = d;
    *data = (double)v;
  }
  return s;
}

static __inline__ int
json_print_double(char **json, char **end, size_t *len,
  double data)
{
  int s;
  if (isnan(data)) {
    if ((s = bufcat(json, end, len, 0, "null"))) return s;
  } else {
    char buf[32];
    sprintf(buf, "%.17g", data);
    if ((s = bufcat(json, end, len, 0, buf))) return s;
  }
  return 0;
}

