/* === char ============================================================= */

static __inline__ int
json_scan_char(int8_t *data, const char **json)
{
  int s = 0;
  json_skip_whitespace(*json);
  if (*((*json)++) != '"') return EINVAL;
  *data = *((*json)++);
  if (*data == '\\' && (**json == '"' || **json == '\\'))
    *data = *((*json)++);
  if (*((*json)++) != '"') return EINVAL;
  return s;
}

static __inline__ int
json_print_char(char **json, char **end, size_t *len,
  int8_t data)
{
  int s;
  char buf[] = { data, 0 };
  if ((s = bufcat(json, end, len, 0, "\""))) return s;
  if ((s = bufcat(json, end, len, 1, buf))) return s;
  if ((s = bufcat(json, end, len, 0, "\""))) return s;
  return 0;
}

/* === array128_char ==================================================== */

static __inline__ int
json_scan_array128_char(int8_t data[128], const char **json)
{
  int s = 0;
  long i;

  json_skip_whitespace(*json);
  switch (*((*json)++)) {
    case '[':
      json_skip_whitespace(*json);
      i = 0;
      while(**json != ']') {
        if (i >= 128) return EINVAL;
        if ((s = json_scan_char(
               &(data[i]), json))) return s;
        json_skip_whitespace(*json);
        if (**json == ',') {
          (*json)++;
          json_skip_whitespace(*json);
        }
        i++;
      }
      break;

    case '{':
      json_skip_whitespace(*json);
      while(**json != '}') {
        char *d;

        if (*((*json)++) != '"') return EINVAL;
        i = strtol(*json, &d, 0);
        if (d == *json || *d != '"' || i<0) return EINVAL;
        *json = d+1;
        json_skip_whitespace(*json);
        if (*((*json)++) != ':') return EINVAL;
        if (i >= 128) return EINVAL;
        if ((s = json_scan_char(
               &(data[i]), json))) return s;
        json_skip_whitespace(*json);
        if (**json == ',') {
          (*json)++;
          json_skip_whitespace(*json);
        }
      }
      break;

    default: return EINVAL;
  }
  (*json)++;
  return s;
}

static __inline__ int
json_print_array128_char(char **json, char **end, size_t *len,
  const int8_t data[128])
{
  int s;
  size_t i;
  if ((s = bufcat(json, end, len, 0, "["))) return s;
  for (i=0; i<128; i++) {
    if (i && (s = bufcat(json, end, len, 0, ","))) return s;
    if ((s = json_print_char(json, end, len,
           data[i]))) return s;
  }
  if ((s = bufcat(json, end, len, 0, "]"))) return s;
  return 0;
}

/* === t_bayes_opt_status_struct ======================================== */

static __inline__ int
json_scan_t_bayes_opt_status_struct(bayes_opt_status_struct *data, const char **json)
{
  int s = 0;
  json_skip_whitespace(*json);
  if (*((*json)++) != '{') return EINVAL;
  json_skip_whitespace(*json);
  while(**json != '}') {
    if (*((*json)++) != '"') return EINVAL;
    if (!strncmp(*json, "text\"", 1+4)) {
      (*json)+= 1+4;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_array128_char(
             data->text, json))) return s;
    } else
    if (!strncmp(*json, "iteration\"", 1+9)) {
      (*json)+= 1+9;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_long(
             &(data->iteration), json))) return s;
    } else
    if (!strncmp(*json, "running\"", 1+7)) {
      (*json)+= 1+7;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_boolean(
             &(data->running), json))) return s;
    } else
    if (!strncmp(*json, "initialized\"", 1+11)) {
      (*json)+= 1+11;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_boolean(
             &(data->initialized), json))) return s;
    } else
      return EINVAL;

    json_skip_whitespace(*json);
    if (**json == ',') {
      (*json)++;
      json_skip_whitespace(*json);
    }
  }
  (*json)++;
  return s;
}

static __inline__ int
json_print_t_bayes_opt_status_struct(char **json, char **end, size_t *len,
  const bayes_opt_status_struct *data)
{
  int s;
  if ((s = bufcat(json, end, len, 0, "{"))) return s;
  if ((s = bufcat(json, end, len, 0, "\"text\":"))) return s;
  if ((s = json_print_array128_char(json, end, len,
         data->text))) return s;
  if ((s = bufcat(json, end, len, 0, ",\"iteration\":"))) return s;
  if ((s = json_print_long(json, end, len,
         data->iteration))) return s;
  if ((s = bufcat(json, end, len, 0, ",\"running\":"))) return s;
  if ((s = json_print_boolean(json, end, len,
         data->running))) return s;
  if ((s = bufcat(json, end, len, 0, ",\"initialized\":"))) return s;
  if ((s = json_print_boolean(json, end, len,
         data->initialized))) return s;
  if ((s = bufcat(json, end, len, 0, "}"))) return s;
  return 0;
}

