/* === short ============================================================ */

static __inline__ int
json_scan_short(int16_t *data, const char **json)
{
  int s = 0;
  long long v;
  char *d;

  v = strtoll(*json, &d, 0);
  if (d == *json) return EINVAL;
  *json = d;
  *(data) = (int16_t)v;
  return s;
}

static __inline__ int
json_print_short(char **json, char **end, size_t *len,
  int16_t data)
{
  int s;
  int64_t v = data;
  if ((s = bufcat_uint64_t(json, end, len, v<0, (uint64_t)(v<0?-v:v))))
    return s;
  return 0;
}

/* === t_bayes_opt_e_sys ================================================ */

static __inline__ int
json_scan_t_bayes_opt_e_sys(bayes_opt_e_sys_detail *data, const char **json)
{
  int s = 0;
  json_skip_whitespace(*json);
  if (*((*json)++) != '{') return EINVAL;
  json_skip_whitespace(*json);
  while(**json != '}') {
    if (*((*json)++) != '"') return EINVAL;
    if (!strncmp(*json, "code\"", 1+4)) {
      (*json)+= 1+4;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_short(
             &(data->code), json))) return s;
    } else
    if (!strncmp(*json, "what\"", 1+4)) {
      (*json)+= 1+4;
      json_skip_whitespace(*json);
      if (*((*json)++) != ':') return EINVAL;
      if ((s = json_scan_string128(
             data->what, json))) return s;
    } else
      return EINVAL;

    json_skip_whitespace(*json);
    if (**json == ',') {
      (*json)++;
      json_skip_whitespace(*json);
    }
  }
  (*json)++;
  return s;
}

static __inline__ int
json_print_t_bayes_opt_e_sys(char **json, char **end, size_t *len,
  const bayes_opt_e_sys_detail *data)
{
  int s;
  if ((s = bufcat(json, end, len, 0, "{"))) return s;
  if ((s = bufcat(json, end, len, 0, "\"code\":"))) return s;
  if ((s = json_print_short(json, end, len,
         data->code))) return s;
  if ((s = bufcat(json, end, len, 0, ",\"what\":"))) return s;
  if ((s = json_print_string128(json, end, len,
         data->what))) return s;
  if ((s = bufcat(json, end, len, 0, "}"))) return s;
  return 0;
}

